// k6-llm-load-test.js
// Run: k6 run -e OPENAI_API_KEY=sk-... k6-llm-load-test.js
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend, Counter } from 'k6/metrics';

const ttft = new Trend('llm_ttft_ms', true);
const tokenRate = new Rate('llm_success_rate');
const totalTokens = new Counter('llm_total_tokens');
const rateLimitErrors = new Counter('llm_429s');

export const options = {
  stages: [
    { duration: '1m', target: 10 },   // ramp to 10 VUs
    { duration: '3m', target: 50 },   // ramp to 50 VUs
    { duration: '2m', target: 50 },   // sustain
    { duration: '1m', target: 0 },    // ramp down
  ],
  thresholds: {
    'http_req_duration': ['p(95)<3000'],   // 95th pct under 3 s
    'llm_success_rate': ['rate>0.99'],
    'llm_429s': ['count<100'],
  },
};

const PROMPTS = [
  'Explain the difference between a monad and a functor in functional programming.',
  'Write a Python decorator that retries a function up to 3 times on exception.',
  'What is a B-tree and why is it used in database indexes?',
  'Describe the SOLID principles with a one-sentence example each.',
  'Write a shell one-liner to find the 10 largest files in the current directory.',
];

export default function () {
  const prompt = PROMPTS[Math.floor(Math.random() * PROMPTS.length)];
  const payload = JSON.stringify({
    model: 'gpt-4o-mini',
    messages: [{ role: 'user', content: prompt }],
    max_tokens: 400,
  });
  const params = {
    headers: {
      Authorization: `Bearer ${__ENV.OPENAI_API_KEY}`,
      'Content-Type': 'application/json',
    },
    timeout: '30s',
  };

  const start = Date.now();
  const res = http.post('https://api.openai.com/v1/chat/completions', payload, params);
  const duration = Date.now() - start;

  if (res.status === 429) {
    rateLimitErrors.add(1);
    tokenRate.add(false);
    sleep(2 + Math.random() * 2);
    return;
  }

  const ok = check(res, {
    'status is 200': (r) => r.status === 200,
    'has choices': (r) => JSON.parse(r.body).choices?.length > 0,
  });
  tokenRate.add(ok);
  if (ok) {
    const body = JSON.parse(res.body);
    totalTokens.add(body.usage?.total_tokens || 0);
    ttft.add(duration);
  }
  sleep(1);
}

# streaming_ttft.py — measure time-to-first-token for streaming completions
# pip install httpx
import time, json, httpx

API_KEY = "sk-YOUR-KEY"

def measure_streaming_ttft(prompt: str, model: str = "gpt-4o-mini") -> dict:
    payload = {
        "model": model,
        "messages": [{"role": "user", "content": prompt}],
        "max_tokens": 512,
        "stream": True,
        "stream_options": {"include_usage": True},
    }
    headers = {"Authorization": f"Bearer {API_KEY}", "Content-Type": "application/json"}
    ttft_ms = None
    chunk_count = 0
    total_tokens = 0
    start = time.monotonic()

    with httpx.stream(
        "POST", "https://api.openai.com/v1/chat/completions",
        json=payload, headers=headers, timeout=60.0,
    ) as response:
        response.raise_for_status()
        for line in response.iter_lines():
            line = line.strip()
            if not line or line == "data: [DONE]":
                continue
            if line.startswith("data: "):
                try:
                    chunk = json.loads(line[len("data: "):])
                except json.JSONDecodeError:
                    continue
                choices = chunk.get("choices", [])
                if choices and ttft_ms is None:
                    if choices[0].get("delta", {}).get("content"):
                        ttft_ms = (time.monotonic() - start) * 1000
                chunk_count += 1
                if chunk.get("usage"):
                    total_tokens = chunk["usage"].get("total_tokens", 0)

    return {
        "ttft_ms": round(ttft_ms or 0, 1),
        "total_ms": round((time.monotonic() - start) * 1000, 1),
        "chunks": chunk_count,
        "total_tokens": total_tokens,
    }

if __name__ == "__main__":
    r = measure_streaming_ttft("Explain entropy in three sentences.")
    print(f"TTFT: {r['ttft_ms']} ms | Total: {r['total_ms']} ms | Tokens: {r['total_tokens']}")
